1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("Quote — base premiums", () => {
6	    it("returns 5 G for an empty item list (processing fee only)", () => {
7	      const result = processScenario({
8	        customer: { yearsWithMHPCO: 0 },
9	        steps: [{ op: "quote" as const, items: [] }],
10	      });
11	      expect(result.results[0]).toEqual({ premium: 5 });
12	    });
13	    it.todo("returns 105 G for a single sword (100 base + 5 fee)");
14	    it.todo("returns 65 G for a single amulet (60 base + 5 fee)");
15	    it.todo("returns 85 G for a single staff (80 base + 5 fee)");
16	    it.todo("returns 45 G for a single potion (40 base + 5 fee)");
17	    it.todo("returns 30 G for a single rune component (25 base + 5 fee)");
18	    it.todo("returns 165 G for a sword and an amulet (100 + 60 + 5 fee)");
19	  });
20	
21	  describe("Quote — component block pricing", () => {
22	    it.todo("returns 55 G for 2 runes (2 × 25 + 5 fee)");
23	    it.todo("returns 65 G for 3 runes (block of 3 alike = 60 + 5 fee)");
24	    it.todo("returns 105 G for 4 runes (no block: 4 × 25 + 5 fee)");
25	    it.todo("returns 80 G for 2 runes + 1 moonstone (no block: different types, 3 × 25 + 5 fee)");
26	    it.todo("returns 125 G for 3 runes + 3 moonstones (two blocks: 60 + 60 + 5 fee)");
27	  });
28	
29	  describe("Quote — item-specific modifiers", () => {
30	    it.todo("adds 50% curse surcharge to cursed item base premium");
31	    it.todo("adds 30% high-enchantment surcharge for enchantment level >= 5");
32	    it.todo("does not add high-enchantment surcharge for enchantment level 4");
33	    it.todo("applies both curse and high-enchantment surcharges to same item");
34	    it.todo("applies item-specific surcharges only to the affected item in a multi-item policy");
35	  });
36	
37	  describe("Quote — policy-wide modifiers", () => {
38	    it.todo("adds 10% first-insurance surcharge to policy base premium");
39	    it.todo("applies 20% loyalty discount for customer with >= 2 years");
40	    it.todo("applies 15% follow-up discount on second quote");
41	    it.todo("applies both loyalty and follow-up discounts together");
42	  });
43	
44	  describe("Quote — rounding", () => {
45	    it.todo("rounds premium up in MHPCO's favor");
46	  });
47	
48	  describe("Quote — integration", () => {
49	    it.todo("newcomer with a cursed sword: premium 165 G");
50	    it.todo("long-standing customer second contract with cursed high-enchantment sword: premium 160 G");
51	  });
52	
53	  describe("Claim — basic payout", () => {
54	    it.todo("applies 100 G deductible per damaged item");
55	    it.todo("reimburses standard damage at full amount minus deductible");
56	    it.todo("reimburses component damage at full amount minus deductible");
57	  });
58	
59	  describe("Claim — enchantment and material modifiers", () => {
60	    it.todo("reimburses enchantment >= 8 items at 50% of damage then deductible");
61	    it.todo("reimburses dragon-material items at full damage minus deductible");
62	    it.todo("applies 50% rule when both enchantment >= 8 and dragon material");
63	  });
64	
65	  describe("Claim — cap", () => {
66	    it.todo("caps total payout at 2x insurance sum per policy");
67	    it.todo("tracks remaining cap across multiple claims");
68	  });
69	
70	  describe("Claim — multiple items", () => {
71	    it.todo("applies deductible per damaged item in a multi-damage event");
72	    it.todo("handles multiple items of the same type in a policy");
73	  });
74	
75	  describe("Claim — payout rounding", () => {
76	    it.todo("rounds payout down in MHPCO's favor");
77	  });
78	
79	  describe("Error handling", () => {
80	    it.todo("rejects unknown item type in quote");
81	    it.todo("rejects claim referencing item not in policy");
82	    it.todo("rejects claim with more damages than insured items of that type");
83	    it.todo("rejects negative damage amount");
84	  });
85	});
